    // Almacena: nombre, tipo y linea donde se declara
    static class Simbolo {
        String nombre;
        String tipo;
        int linea;
        String categoria;
        boolean inicializada;

        Simbolo(String nombre, String tipo, int linea, String categoria, boolean inicializada) {
            this.nombre    = nombre;
            this.tipo      = tipo;
            this.linea     = linea;
            this.categoria = categoria;
            this.inicializada = inicializada;
        }
    }

