    // Mapa: switchId -> lugar (temporal de la expresion)
    private static java.util.HashMap<Integer, String> mapaLugarSwitch = new java.util.HashMap<>();

    // Mapa: switchId -> tiene_default (true/false)
    private static java.util.HashMap<Integer, Boolean> mapaDefaultSwitch = new java.util.HashMap<>();
    
    // Mapa: whileId -> etiqueta de inicio
    private static java.util.HashMap<Integer, String> mapaEtqInicioWhile = new java.util.HashMap<>();

    // Pilas para break anidados
    static java.util.Stack<String> pilaBreak = new java.util.Stack<>();

    static java.util.Stack<Integer> pilaContadorWhile = new java.util.Stack<>();

    static java.util.Stack<java.util.ArrayList<String>> pilaArgumentos = new java.util.Stack<>();

    // Guarda el tipo del switch
    private void setTipoSwitch(int switchId, String tipo) {
        mapaTipoSwitch.put(switchId, tipo);
    }
    
    // Obtiene el tipo del switch
    private String getTipoSwitch(int switchId) {
        return mapaTipoSwitch.getOrDefault(switchId, "desconocido");
    }
    
    // Mapa: switchId -> lista de constantes usadas en cases
    private static java.util.HashMap<Integer, java.util.ArrayList<String>> mapaConstantesSwitch = new java.util.HashMap<>();
    
    // Valida que no haya constantes duplicadas en el mismo switch
    private void agregarConstanteSwitch(int switchId, String constante, int linea) {
        if (!mapaConstantesSwitch.containsKey(switchId)) {
            mapaConstantesSwitch.put(switchId, new java.util.ArrayList<>());
        }
        java.util.ArrayList<String> constantes = mapaConstantesSwitch.get(switchId);
        if (constantes.contains(constante)) {
            errorSemantico("Linea " + linea + ": constante de case duplicada: " + constante);
        } else {
            constantes.add(constante);
        }
    }
    
    // Valida que solo haya un default por switch
    private void marcarDefaultUsado(int switchId, int linea) {
        if (mapaDefaultSwitch.getOrDefault(switchId, false)) {
            errorSemantico("Linea " + linea + ": solo puede haber un 'default' por switch");
        } else {
            mapaDefaultSwitch.put(switchId, true);
        }
    }

    // Guarda el lugar (temporal) de la expresion del switch
    private void setLugarSwitch(int id, String lugar) { 
        mapaLugarSwitch.put(id, lugar); 
    }
    
    // Obtiene el lugar de la expresion del switch
    private String getLugarSwitch(int id) { 
        return mapaLugarSwitch.getOrDefault(id, "?"); 
    }

    // Mapa: switchId -> casoId -> etiqueta de fin del case
    private static java.util.HashMap<Integer, java.util.HashMap<Integer, String>> mapaEtqCasos = new java.util.HashMap<>();

    // Guarda la etiqueta de fin de un case especifico
    private void setEtqCasoActual(int swId, int casoId, String etq) {
        mapaEtqCasos.computeIfAbsent(swId, k -> new java.util.HashMap<>()).put(casoId, etq);
    }
    
    // Obtiene la etiqueta de fin de un case
    private String getEtqCasoActual(int swId, int casoId) {
        return mapaEtqCasos.getOrDefault(swId, new java.util.HashMap<>())
                           .getOrDefault(casoId, "_sw" + swId + "_end");
    }

    // Guarda la etiqueta de inicio de un do-while
    private void setEtqInicioWhile(int id, String etq) {
        mapaEtqInicioWhile.put(id, etq);
    }

    // Obtiene la etiqueta de inicio de un do-while
    private String getEtqInicioWhile(int id) {
        return mapaEtqInicioWhile.getOrDefault(id, "_dowhile" + id + "_start");
    }

